import requests

BASE_URL = "http://localhost:5000"
TIMEOUT = 30

def test_post_api_auth_login_user_login():
    # Valid login credentials (from PRD instructions)
    valid_email = "tawandamhch@gmail.com"
    valid_password = "AlPha21Thxkvng"  # strong password

    login_url = f"{BASE_URL}/api/auth/login"
    headers = {"Content-Type": "application/json"}

    # Test: Login with valid credentials
    valid_payload = {
        "email": valid_email,
        "password": valid_password
    }
    try:
        valid_response = requests.post(login_url, json=valid_payload, headers=headers, timeout=TIMEOUT)
    except requests.RequestException as e:
        assert False, f"Request failed during valid login attempt: {e}"

    assert valid_response.status_code == 200, f"Expected 200 but got {valid_response.status_code} for valid login"
    try:
        valid_json = valid_response.json()
    except ValueError:
        assert False, "Response is not valid JSON for valid login"

    assert "token" in valid_json, "JWT token missing in response for valid login"
    assert "seller" in valid_json, "Seller details missing in response for valid login"
    # Optionally, verify token is a non-empty string
    token = valid_json.get("token")
    assert isinstance(token, str) and token.strip(), "Invalid JWT token format"

    # Test: Login with invalid credentials (wrong password)
    invalid_payload = {
        "email": valid_email,
        "password": "WrongPass123!"
    }
    try:
        invalid_response = requests.post(login_url, json=invalid_payload, headers=headers, timeout=TIMEOUT)
    except requests.RequestException as e:
        assert False, f"Request failed during invalid login attempt: {e}"

    assert invalid_response.status_code == 401, f"Expected 401 but got {invalid_response.status_code} for invalid login"

test_post_api_auth_login_user_login()

import requests

BASE_URL = "http://localhost:5000"
TIMEOUT = 30

def test_post_api_otp_verify_verify_otp_code():
    email = "testotpverify@example.com"
    otp_type = "registration"

    # Step 1: Send OTP to get a valid OTP code
    send_otp_url = f"{BASE_URL}/api/otp/send"
    send_otp_payload = {"email": email, "type": otp_type}
    try:
        send_resp = requests.post(send_otp_url, json=send_otp_payload, timeout=TIMEOUT)
        assert send_resp.status_code == 200, f"Failed to send OTP: {send_resp.text}"
    except Exception as e:
        raise AssertionError(f"Exception during sending OTP: {str(e)}")

    # Step 2: Verify OTP code - success case
    verify_otp_url = f"{BASE_URL}/api/otp/verify"
    valid_otp_code = "123456"
    verify_payload_valid = {"email": email, "otp": valid_otp_code, "type": otp_type}
    resp_valid = None
    try:
        resp_valid = requests.post(verify_otp_url, json=verify_payload_valid, timeout=TIMEOUT)
        # Accepting 200 as success, or 400 if OTP invalid
        assert resp_valid.status_code in (200, 400), (
            f"Unexpected status code for valid OTP attempt: {resp_valid.status_code}, body: {resp_valid.text}"
        )
    except Exception as e:
        raise AssertionError(f"Exception during OTP verification: {str(e)}")

    # Step 3: Verify OTP code - invalid/expired OTP (expect 400 or 404)
    invalid_otp_code = "000000"
    verify_payload_invalid = {"email": email, "otp": invalid_otp_code, "type": otp_type}
    try:
        resp_invalid = requests.post(verify_otp_url, json=verify_payload_invalid, timeout=TIMEOUT)
        assert resp_invalid.status_code in (400, 404), (
            f"Expected 400 or 404 for invalid/expired OTP, got {resp_invalid.status_code}, body: {resp_invalid.text}"
        )
    except Exception as e:
        raise AssertionError(f"Exception during invalid OTP verification test: {str(e)}")

test_post_api_otp_verify_verify_otp_code()

import requests

BASE_URL = "http://localhost:5000"

AUTH_USERNAME = "tawandamhch@gmail.com"


def test_post_api_otp_resend_resend_otp_code():
    url = f"{BASE_URL}/api/otp/resend"
    payload = {
        "email": AUTH_USERNAME,
        "type": "registration"
    }
    headers = {
        "Content-Type": "application/json"
    }
    try:
        response = requests.post(
            url,
            json=payload,
            headers=headers,
            timeout=30
        )
    except requests.RequestException as e:
        assert False, f"Request failed: {e}"

    assert response.status_code == 200, f"Expected status 200 but got {response.status_code}"
    try:
        json_response = response.json()
    except ValueError:
        assert False, "Response is not valid JSON"

    assert (
        ("message" in json_response and "resent" in json_response["message"].lower())
        or ("otp" in json_response and json_response.get("otp") is not None)
        or ("status" in json_response and json_response["status"].lower() in ["otp resent", "success"])
    ), f"Response JSON does not confirm OTP resent: {json_response}"

test_post_api_otp_resend_resend_otp_code()
